var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"어지간히 끈질기군...... 이쯤 되면 포기할 법도 한데......","JPN":"とんでもなくしつこいな……いい加減、諦めてもいい頃だが……","ENG":"She's still as tenacious as ever... You'd think she'd give up by now...","TWN":"真是頑強……都到這種地步了，妳也該放棄了吧……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"포기따윈 생각해 본 적도 없다.","JPN":"諦めようなどと考えたことは一度もない。","ENG":"I've never even considered giving up.","TWN":"我從沒想過要放棄。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"명심하도록. 내가 있는 한 너희들은 방주에 손가락 하나 못 대.","JPN":"肝に銘じておけ。私がいる限り、\\n貴様たちは箱舟に指一本触れることはできん。","ENG":"Mark my words. You won't lay a finger on that Ark as long as I live.","TWN":"給我記好了，只要我活著的一天，你們就休想靠近方舟一步。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"큭...... 크큭......","JPN":"クッ……ククッ……","ENG":"Hah... Hah hah...","TWN":"呵……呵呵……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"혼자만 고고한 척 하기는......","JPN":"自分だけ高尚ぶりやがって……","ENG":"Look at you, pretending to be all noble...","TWN":"裝什麼清高……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"어차피 우리와 별반 다를 것도 없는 주제에...... 구역질나는군......","JPN":"どうせ俺らと大差ないくせして……反吐が出るぜ……","ENG":"You're no different from us... You make me vomit...","TWN":"妳和我們又沒什麼不同……真令人噁心……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......뭐?","JPN":"……何だと？","ENG":"What?","TWN":"……什麼？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"아...... 젠장. 원본만 잡아먹었다면 나도 이 따위 병정놀이는 진작에 때려치웠을 텐데......","JPN":"クソッ……オリジナルさえ捕まえて喰っていれば、\\n俺もこんなくだらん兵隊ごっこはとっくにやめてるはずなんだが……","ENG":"Oh... Crap. If only I devoured my original... I'd have stopped playing soldier a long time ago...","TWN":"啊……該死，只要吃了本體，我就不用玩這種士兵遊戲了……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"하긴 이젠 너무 늦어버렸나?","JPN":"まあ、もはや何もかも手遅れだがな。","ENG":"Then again, I guess it's too late for that now.","TWN":"但已經太遲了吧？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"무슨 뜻이지? 늦다니 뭐가......?","JPN":"何のことだ？　手遅れとはいったい……？","ENG":"What do you mean? Too late for what?","TWN":"什麼意思？什麼太遲了……？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"우리 전대장은 너랑 다르게 부하 목숨 따위는 신경 쓰지 않거든.","JPN":"我らが戦隊長はお前と違って、部下の命など眼中にないお方なのさ。","ENG":"Unlike you, our boss doesn't give a damn about her troops.","TWN":"我們的隊長和妳不同，在她眼裡，部下的性命什麼的，根本就不重要。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"이런, 가엾은...... 이름이 뭐더라?","JPN":"おぉ、哀れな……名前は何と言ったかな？","ENG":"Oh, poor thing... What was his name again?","TWN":"哎呀，真可憐……他叫什麼名字來著？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_TANK_MOVE"},{"id":"L20_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"하긴, 뭐든 상관없지. 어차피 곧 재가 될 마당에.","JPN":"まあ、何であろうと構わん。どうせすぐに灰となるのだから。","ENG":"Well, I suppose it doesn't matter. He'll be a pile of ash soon.","TWN":"算了，無所謂，反正很快就會化成灰燼的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"바퀴벌레가 날아가기 전에 잿더미로 만들어 버려라!","JPN":"ゴキブリが飛び立つ前に消し炭にしてしまえ！","ENG":"Turn that Roach into pulp before she flies away!","TWN":"在蟑螂飛走之前把她轟成灰屑！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"포격 개시!","JPN":"砲撃開始！","ENG":"Fire!","TWN":"開始砲擊！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이 자식......! 설마 아군을 미끼로 삼다니!","JPN":"こいつ……！　まさか、味方を囮にするとは！","ENG":"That scumbag! She's used her own troops as bait!","TWN":"這傢伙……！竟然把自己人當成誘餌！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"빌어먹을! 전대자아아앙!!","JPN":"クソッタレェ！　戦隊長ォォオ！！","ENG":"Damn it! Commanderrr!!","TWN":"該死！隊長——！！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"흐응...... 좀 기대했는데 역시 허탕이네.","JPN":"ふーん……ちょっと期待してたけど、やっぱり無駄骨だったわね。","ENG":"Hmm... I got my hopes up a bit this time, but I guess we didn't get her.","TWN":"哼……我還稍微期待了一下，但果然又失敗了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"그쪽은 어때?","JPN":"そっちはどうだったの？","ENG":"How about you?","TWN":"你那邊怎麼樣？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWORD_ADMIN_CORRUPT_MAZE","text":{"KOREA":"여기도 없습니다.","JPN":"こちらにもありません。","ENG":"Nothing here either.","TWN":"這裡也沒有。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SWORD_ADMIN_CORRUPT_MAZE","text":{"KOREA":"어서 그 바퀴벌레를 잡아야 이 웃긴 짓도 끝낼 텐데요.","JPN":"早くあのゴキブリを仕留めたいものです。\\nこの馬鹿げたマネを終わらせるためにも。","ENG":"I can't wait to get that Roach so we won't have to put up with this nonsense anymore.","TWN":"我們得抓住那隻蟑螂，才能結束這場鬧劇。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"닥쳐. 그런 소리가 <color=#ffd34c>전대장</color> 귀에 들어갔다간 곱게 못 죽으니까.","JPN":"口に気をつけなさい。そんな話が<color=#ffd34c>戦隊長</color>の\\n耳に入ったら、楽には死なせてもらえないわよ。","ENG":"Shush! If the <color=#ffd34c>Commander</color> hears you say that, you're going to die ugly.","TWN":"住口。萬一讓<color=#ffd34c>隊長</color>聽到，你就完蛋了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SWORD_ADMIN_CORRUPT_MAZE","text":{"KOREA":"아, 그렇죠.","JPN":"あぁ、そうでしたね。","ENG":"Oh, that's true.","TWN":"喔，說得也是。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_ADMIN_CORRUPT_MAZE","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"SWORD_ADMIN_CORRUPT_MAZE","text":{"KOREA":"하긴 인간이랑 노는 데 정신 팔린 <color=#ffd34c>전대장</color> 나리니까요.","JPN":"何せ人間とごっこ遊びに興じている<color=#ffd34c>戦隊長</color>殿であられますから。","ENG":"Our great so-called <color=#ffd34c>Commander</color> is obsessed with playing with her human.","TWN":"也是，她現在可是和人類玩的不亦樂乎的<color=#ffd34c>隊長</color>呢。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SWORD_ADMIN_CORRUPT_MAZE","text":{"KOREA":"하지만 괜찮을까요? 이번에도 실패하면 아예 방주째 날려 버릴 모양이던데?","JPN":"しかし、大丈夫なのですか？\\n今回も失敗すれば箱舟ごと吹き飛ばすつもりのようですが。","ENG":"But are you sure about this? If we fail again, I think she might blow the entire Ark away.","TWN":"但真的沒問題吧？如果這次也失敗，她可能會直接把整個方舟炸爛啊？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SWORD_ADMIN_CORRUPT_MAZE","text":{"KOREA":"그러면 우린 영원히 반쪽 짜리로 살아야 할 겁니다.","JPN":"そうなれば、私たちは永遠に半分欠けた存在になってしまいます。","ENG":"That will leave us incomplete forever.","TWN":"那麼，我們就只能永遠以不上不下的存在活下去了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"글쎄...... 나도 안 그랬으면 좋겠는데.","JPN":"さあね……私もそうなってほしくはないのよね。","ENG":"I don’t know... I'm hoping it won't come to that.","TWN":"是啊……我也不希望發生這種事。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWORD_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"아 참. 못 움직이는 애들은 알아서 잡아 먹어.","JPN":"そうそう。動けない子たちは適当につまんで食べちゃってね。","ENG":"Oh, by the way. If you see anyone that can't move anymore, help yourselves.","TWN":"對了，那些無法動彈的孩子們就直接吃掉吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SWORD_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"우리 애들, 많이 먹고 쑥쑥 커야지?","JPN":"可愛い子どもたち、たくさん食べて大きくおなり……！","ENG":"I want you to eat well and become big and strong, kids.","TWN":"我們的孩子們都得多吃點，一點一點地成長茁壯才行喔？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"쿨럭! 쿨럭......!","JPN":"コホッ！　コホッ……！","ENG":"*Cough!* *Cough!*","TWN":"咳咳！咳咳……！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MOVEMENT_12"},{"id":"L4_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"작전기록...... 녹음.","JPN":"作戦記録……録音。","ENG":"Operation... log.","TWN":"作戰記錄……錄音。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"도플갱어가 동결이 풀린 함체를 노리기 시작했다...... 어려운 상황이다.","JPN":"ドッペルゲンガーは凍結の解かれた船体を狙い撃ちし始めた……\\n厳しい状況だ。","ENG":"The Doppelgangers began to go for the ship with its stasis down... The situation seems difficult.","TWN":"二重身開始盯著解除凍結的艦體了……情況不妙。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만...... 이걸로 당분간은 시간을 벌었다.","JPN":"だが……これで幾許かの時間は稼げた。","ENG":"However... I've managed to buy some time...","TWN":"但……我至少爭取了一些時間。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이제 방주로 귀환한다. 관리자께서 반드시 방법을 찾아 주시기를......","JPN":"これより箱舟へ帰還する。管理者様が方法を見つけてくださることを……","ENG":"I will now return to the Ark. Hopefully the Administrator will find a way...","TWN":"現在返回方舟。管理者一定會找出什麼辦法……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"응? 저건......?","JPN":"む？　あれは……？","ENG":"Huh? Isn't that...","TWN":"嗯？那是……？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_ADMIN_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"무슨 일이지, 이수연? 왜 이런 데 나와 있나?","JPN":"どうした、カナミ。なぜこんなところに出てきている？","ENG":"What's going on, Sooyeon? What are you doing out here?","TWN":"怎麼了，李秀妍？妳為什麼出來了？"},"stage":{"bg":"SS_ADMIN_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이 탈리 마크, 네가 새긴 건가?","JPN":"このタリーマークはあなたが刻み付けたの？","ENG":"Did you make these tally marks?","TWN":"這些塔利標記，是妳刻的嗎？"},"stage":{"bg":"SS_ADMIN_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"음...... 그랬던 것 같군. 언제부터인지 그만두게 됐지만.","JPN":"うむ……そうだったな。いつからかやめてしまったがな。","ENG":"Hmm... It appears so. Although I've stopped doing since... I don't know.","TWN":"嗯……沒錯。不知從什麼時候開始，就沒有再刻了。"},"stage":{"bg":"SS_ADMIN_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>언제부터인지</color>...... 라.","JPN":"<color=#ffd34c>いつからか</color>……か。","ENG":"<color=#ffd34c>You don't know</color>... huh.","TWN":"<color=#ffd34c>不知從什麼時候</color>……是嗎。"},"stage":{"bg":"SS_ADMIN_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그보다 포격을 저지하는 데 성공했다.","JPN":"それより、砲撃を阻止することに成功した。","ENG":"By the way, I've managed to stop the enemy's artillery.","TWN":"比起這個，我成功阻止了炮擊。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"당분간 잠잠할 테니, 이제 안전하게 대원들을 구할 방법만 마련하면 돼.","JPN":"しばらくは攻撃も止むはずだ。\\nあとは安全に隊員たちを連れ出す方法を探せばいい。","ENG":"It should be quiet for the time being. We just need to find a way to save the troops.","TWN":"攻勢應該會減緩一些，我們可以趁現在想出拯救隊員們的辦法。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"설령 그 사이에 어떤 적이 쳐들어 오더라도, 내가 반드시 막을 테니 말이다.","JPN":"その間にどんな敵が攻め込んでこようと、私が必ず食い止めてやる。","ENG":"Even if we have any more hostiles come at us, I'll stop them no matter what.","TWN":"這段期間就算又有敵人來襲，我也一定會阻止他們的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......그만해.","JPN":"……やめて。","ENG":"That's enough.","TWN":"……夠了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"뭐......?","JPN":"何だと……？","ENG":"What?","TWN":"什麼……？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이제 그만하라고.","JPN":"もうやめなさいと言っているの。","ENG":"I said, that's enough.","TWN":"已經足夠了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"넌 충분히 할 만큼 했어.","JPN":"あなたはもう十分頑張ったわ。","ENG":"You've done plenty already.","TWN":"妳已經做得夠多了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러니...... 이제 그만둬.","JPN":"だから……もうやめなさい。","ENG":"So... Stop it.","TWN":"所以……住手吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"무슨 말을 하고 싶은 거냐? 그만두라니 뭘?","JPN":"どういうことだ？　やめろとは、何をやめろと言っている？","ENG":"What are you talking about? Stop what, exactly?","TWN":"妳在說什麼？什麼夠了？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......보아하니 너 자신도 아직 모르는 것 같군.","JPN":"……どうやらあなた自身まだ気づいていないようね。","ENG":"It seems you don't even realize it yourself.","TWN":"……看來妳自己還沒有意識到。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아무래도 확신이 부족해서 그냥 지켜보고 있었지만......","JPN":"確信が持てなかったものだからしばらく静観していたけれど……","ENG":"I was just watching because I wasn't entirely sure...","TWN":"我因為還不太能確定，所以一直在觀察……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지금의 네 모습을 보니 역시 내 생각이 맞았던 것 같아.","JPN":"今のあなたの様子からすると、私の予想は正しかったみたい。","ENG":"But seeing you now makes me realize I was right all along.","TWN":"但看到妳現在的樣子，我的推斷果然是正確的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"뭐가 맞았다는 거냐? 말 돌리지 말고 확실하게 얘기해!","JPN":"何の話だ？　もったいぶった言い方はやめろ。\\nはっきり言ったらどうなんだ！","ENG":"Right about what? Stop beating around the bush and say what you mean!","TWN":"什麼正確？不要拐彎抹角了，妳直說吧！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"간단해.","JPN":"では、はっきり言わせてもらうわ。","ENG":"It's simple.","TWN":"很簡單。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"너도 진짜 류드밀라가 아니라는 말이다.","JPN":"あなたも本物のリュドミラではないと言っているの。","ENG":"I'm saying you're not the real Lyudmila either...","TWN":"妳也不是真正的盧德米拉。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그림자.","JPN":"シャドウ。","ENG":"Shadow.","TWN":"暗影。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};